import { useEffect, useMemo, useState } from 'react'
import './index.css'
import { applyMove, createInitialGame, type Board, type Direction } from './game'

const keyToDirection: Record<string, Direction> = {
  ArrowUp: 'up',
  ArrowDown: 'down',
  ArrowLeft: 'left',
  ArrowRight: 'right',
  w: 'up',
  a: 'left',
  s: 'down',
  d: 'right',
  W: 'up',
  A: 'left',
  S: 'down',
  D: 'right',
}

const tileClassName = (value: number) => `tile tile-${value}`

const boardHas2048 = (board: Board): boolean => board.flat().some((value) => value >= 2048)

function App() {
  const [game, setGame] = useState(() => createInitialGame())

  const move = (direction: Direction) => {
    setGame((current) => {
      if (current.gameOver) {
        return current
      }

      return applyMove(current.board, direction, current.score)
    })
  }

  const restart = () => setGame(createInitialGame())

  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      const direction = keyToDirection[event.key]
      if (!direction) {
        return
      }

      event.preventDefault()
      move(direction)
    }

    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [])

  const status = useMemo(() => {
    if (game.gameOver) {
      return 'Game over'
    }
    if (boardHas2048(game.board)) {
      return 'You made 2048!'
    }
    return 'Use arrow keys or WASD to play'
  }, [game.board, game.gameOver])

  return (
    <main className="app-shell">
      <section className="game-card">
        <header className="topbar">
          <div>
            <h1>2048</h1>
            <p className="subtitle">Join matching tiles to reach 2048.</p>
          </div>
          <div className="score-panel" aria-label="Current score">
            <span className="score-label">Score</span>
            <strong className="score-value">{game.score}</strong>
          </div>
        </header>

        <div className="controls">
          <p className="status" aria-live="polite">
            {status}
          </p>
          <button type="button" className="restart-button" onClick={restart}>
            Restart
          </button>
        </div>

        <section className="board" aria-label="2048 board">
          {game.board.map((row, rowIndex) =>
            row.map((value, colIndex) => (
              <div
                key={`${rowIndex}-${colIndex}`}
                className={tileClassName(value)}
                aria-label={`Tile ${rowIndex + 1}-${colIndex + 1}: ${value || 'empty'}`}
              >
                {value !== 0 ? value : ''}
              </div>
            )),
          )}
        </section>

        <p className="help-text">Controls: Arrow keys or W A S D</p>
      </section>
    </main>
  )
}

export default App
EOF

